mapper.select:
SELECT * FROM sys_login_log ll

    ll.deleted = 0

        AND ll.username LIKE CONCAT('%', #{username}, '%')


        AND ll.ip_address LIKE CONCAT('%', #{ipAddress}, '%')


        AND ll.status = #{status}


        AND ll.login_time >= #{startTime}


        AND ll.login_time <= #{endTime}


ORDER BY ll.login_time DESC
LIMIT #{offset}, #{limit}

SELECT * FROM sys_login_log ll

    ll.deleted = 0

        AND ll.username LIKE CONCAT('%', #{username}, '%')


        AND ll.ip_address LIKE CONCAT('%', #{ipAddress}, '%')


        AND ll.status = #{status}


        AND ll.login_time >= #{startTime}


        AND ll.login_time <= #{endTime}


ORDER BY ll.login_time DESC

SELECT COUNT(*) FROM sys_login_log ll

    ll.deleted = 0

        AND ll.username LIKE CONCAT('%', #{username}, '%')


        AND ll.ip_address LIKE CONCAT('%', #{ipAddress}, '%')


        AND ll.status = #{status}


        AND ll.login_time >= #{startTime}


        AND ll.login_time <= #{endTime}

SELECT DATE(login_time) as date, COUNT(*) as count
FROM sys_login_log
WHERE login_time >= #{startTime}
  AND login_time <= #{endTime}
GROUP BY DATE(login_time)
ORDER BY date

SELECT SUM(CASE WHEN status = 1 THEN 1 ELSE 0 END) as success,
       SUM(CASE WHEN status = 0 THEN 1 ELSE 0 END) as fail,
       COUNT(*)                                    as total
FROM sys_login_log
WHERE login_time >= #{startTime}
  AND login_time <= #{endTime}

SELECT COUNT(DISTINCT username)
FROM sys_login_log
WHERE login_time >= #{startTime}
  AND login_time <= #{endTime}
  AND status = 1

SELECT HOUR(login_time) as hour, COUNT(*) as count
FROM sys_login_log
WHERE login_time >= #{startTime}
  AND login_time <= #{endTime}
GROUP BY HOUR(login_time)
ORDER BY hour
